package com.infy.inventrack.gateway.config; import org.springframework.context.annotation.*; import org.springframework.security.config.Customizer; import org.springframework.security.config.annotation.web.reactive.EnableWebFluxSecurity; import org.springframework.security.config.web.server.ServerHttpSecurity; import org.springframework.security.core.userdetails.*; import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder; import org.springframework.security.crypto.password.PasswordEncoder; import org.springframework.security.web.server.SecurityWebFilterChain; @Configuration @EnableWebFluxSecurity public class SecurityConfig { @Bean SecurityWebFilterChain chain(ServerHttpSecurity http){ return http.csrf(ServerHttpSecurity.CsrfSpec::disable).authorizeExchange(ex->ex.pathMatchers("/actuator/**").permitAll().anyExchange().authenticated()).httpBasic(Customizer.withDefaults()).build(); } @Bean MapReactiveUserDetailsService users(PasswordEncoder e){ return new MapReactiveUserDetailsService(User.withUsername("admin").password(e.encode("Admin@123")).roles("ADMIN").build(), User.withUsername("customer").password(e.encode("Customer@123")).roles("CUSTOMER").build()); } @Bean PasswordEncoder encoder(){ return new BCryptPasswordEncoder(); } }
